"content": {
"topic": "Tree Transformation Reconstruction",
"problem_statement": "Reconstructing a valid sequence of sibling-merge operations that transforms an initial rooted tree into a final rooted tree.",
"structural_invariants": {
"node_preservation": "The final tree nodes must correspond to a subset of initial nodes or merged groups.",
"parent_child_invariant": "If u is a child of p in the final tree, u must be a descendant of p in the initial tree, with intermediate nodes merged into p or u.",
"sibling_order_invariant": "The relative order of siblings must be preserved during merging."
},
"reconstruction_logic": {
"approach": "Bottom-up post-order traversal with greedy matching.",
"steps": [
{
"step": "Mapping Final Nodes to Initial Nodes",
"description": "Define f(u) as the set of initial nodes composing final node u. Each final node represents a contiguous range of initial nodes sharing a parent."
},
{
"step": "Merge Sequence Derivation",
"description": "Identify redundant nodes and partition initial children into contiguous blocks that match the final children structure."
},
{
"step": "Formalizing the Sequence",
"description": "Identify all pairs (u, v) of adjacent siblings to be merged via post-order traversal."
}
]
}
},
"metadata": {
"version": "1.0",
"complexity": "high"
}
}

